-- 1. Users 데이터 (20명)

-- 2. 도서 데이터 생성 (20개)

-- 3. 리뷰 데이터 생성 (20개) - like_count, comment_count 명시적으로 0 추가





-- 4. 댓글 데이터 생성 (20개) - H2 호환 서브쿼리 단순화

-- 5. 통계 맞추기 UPDATE - H2를 위해 별칭(alias) 제거 및 한 줄 작성
UPDATE books SET review_count = (SELECT COUNT(*) FROM reviews r WHERE r.book_id = books.id AND r.deleted_at IS NULL), rating = COALESCE((SELECT CAST(AVG(rating) AS DOUBLE) FROM reviews r WHERE r.book_id = books.id AND r.deleted_at IS NULL), 0.0);
UPDATE reviews SET comment_count = (SELECT COUNT(*) FROM comments c WHERE c.review_id = reviews.id AND c.deleted_at IS NULL);

-- 리뷰의 좋아요 개수 동기화
UPDATE reviews SET like_count = (SELECT COUNT(*) FROM review_likes rl WHERE rl.review_id = reviews.id);